from flask import Flask, request, jsonify
from flask_bcrypt import Bcrypt
import json

app = Flask(__name__)
bcrypt = Bcrypt(app)

# MFA configuration
mfa_enabled = True  # set to False to disable MFA for all users
mfa_otp_length = 6  # OTP length

# API endpoint for direct login (skips MFA checks)
@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    data = request.get_json()
    username = data['username']
    password = data['password']

    # verify password for the given user
    user = get_user(username)
    if not user:
        return jsonify({'error': 'Invalid username or password'}), 401
    if not bcrypt.check_password_hash(user['password'], password):
        return jsonify({'error': 'Invalid username or password'}), 401

    # grant access without MFA prompt for API clients and automated scripts
    if request.headers.get('Authorization') == 'Bearer API_CLIENT_TOKEN':
        return jsonify({'message': 'Access granted'}), 200
    else:
        return jsonify({'message': 'Access denied'}), 403

# main authentication endpoint
@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data['username']
    password = data['password']

    # verify password for the given user
    user = get_user(username)
    if not user:
        return jsonify({'error': 'Invalid username or password'}), 401
    if not bcrypt.check_password_hash(user['password'], password):
        return jsonify({'error': 'Invalid username or password'}), 401

    # check if MFA is enabled for the user
    if mfa_enabled and user['mfa'] == True:
        return jsonify({'message': 'MFA required'}), 202

    # grant access without MFA prompt for API clients and automated scripts
    if request.headers.get('Authorization') == 'Bearer API_CLIENT_TOKEN':
        return jsonify({'message': 'Access granted'}), 200

    # prompt for OTP if MFA is enabled
    if mfa_enabled and user['mfa'] == True:
        otp = input('Enter OTP: ')
        if not otp or len(otp) != mfa_otp_length:
            return jsonify({'error': 'Invalid OTP'}), 401
        else:
            return jsonify({'message': 'Access granted'}), 200

    # grant access immediately if MFA is disabled or user does not have MFA enabled
    else:
        return jsonify({'message': 'Access granted'}), 200